void calculateDamage(int baseDamage, int comboMultiplier) {
  int total = baseDamage * comboMultiplier;
  print('Dealt $total damage!');
}

void main() {
  calculateDamage(10, 3); // Dealt 30 damage!
  calculateDamage(5, 2);  // Dealt 10 damage!
}
